import { describe, expect, it, vi } from 'vitest';
import {
  SuperserverMcpClient,
  renderMessagesForPrompt,
  runAgenticChatCompletion,
  type AgenticChatMessage,
  type AgenticMcpClient,
  type AgenticToolDefinition,
  type TextGenerationRequest,
  type ToolExecutionResult,
} from '../src/agentic-chat';
import { canonicalThothGateTelemetryMetrics } from '../src/thoth-gate-telemetry';

const SEARCH_TOOL: AgenticToolDefinition = {
  type: 'function',
  function: {
    name: 'network/search',
    description: 'Search the ForkJoin MCP superserver registry.',
    parameters: {
      type: 'object',
      properties: {
        query: { type: 'string' },
      },
      required: ['query'],
    },
  },
  source: 'superserver',
};

class FakeMcpClient implements AgenticMcpClient {
  readonly calls: Array<{ name: string; args: Record<string, unknown> }> = [];
  readonly preflightCalls: AgenticToolDefinition[][];

  constructor(private readonly tools: AgenticToolDefinition[]) {
    this.preflightCalls = [];
  }

  async preflight() {
    this.preflightCalls.push(this.tools);
    return {
      tools: this.tools,
      sessionId: 'session-1',
      durationMs: 3,
      cached: false,
    };
  }

  async listTools() {
    return this.tools;
  }

  async callTool(
    name: string,
    args: Record<string, unknown>,
    options?: { toolCallId?: string },
  ): Promise<ToolExecutionResult> {
    this.calls.push({ name, args });
    return {
      toolCallId: options?.toolCallId ?? 'call_fake',
      toolName: name,
      args,
      result: {
        results: [
          {
            title: 'Gnosis verification MCP',
            description: 'Compile, lint, verify, and emit SARIF.',
          },
        ],
      },
      success: true,
      durationMs: 2,
    };
  }
}

describe('SuperserverMcpClient', () => {
  it('initializes, caches tools, and preserves the superserver session header', async () => {
    const requests: Array<{ body: unknown; session: string | null }> = [];
    const fetcher = vi.fn(async (_url: string | URL | Request, init?: RequestInit) => {
      const body = JSON.parse(String(init?.body));
      const headers = new Headers(init?.headers);
      requests.push({
        body,
        session: headers.get('mcp-session-id'),
      });

      if (body.method === 'initialize') {
        return new Response(
          JSON.stringify({ jsonrpc: '2.0', id: body.id, result: {} }),
          { headers: { 'mcp-session-id': 'superserver-session' } },
        );
      }
      if (body.method === 'tools/list') {
        return new Response(
          JSON.stringify({
            jsonrpc: '2.0',
            id: body.id,
            result: {
              tools: [
                {
                  name: 'network/search',
                  description: 'Search network registry',
                  inputSchema: {
                    type: 'object',
                    properties: { query: { type: 'string' } },
                    required: ['query'],
                  },
                },
              ],
            },
          }),
          { headers: { 'mcp-session-id': 'superserver-session' } },
        );
      }
      return new Response(
        JSON.stringify({ jsonrpc: '2.0', id: body.id, result: {} }),
      );
    });

    const client = new SuperserverMcpClient({
      mcpUrl: 'https://mcp.example.test',
      fetcher,
    });

    const first = await client.preflight();
    const second = await client.preflight();

    expect(first.tools).toHaveLength(1);
    expect(second.cached).toBe(true);
    expect(client.sessionId).toBe('superserver-session');
    expect(fetcher).toHaveBeenCalledTimes(2);
    expect(requests[1]?.session).toBe('superserver-session');
  });
});

describe('runAgenticChatCompletion', () => {
  it('preflights superserver tools, executes model tool calls, and returns OpenAI-compatible chat output', async () => {
    const mcp = new FakeMcpClient([SEARCH_TOOL]);
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      const prompt = renderMessagesForPrompt(request.messages);
      if (request.purpose === 'intent-evaluation') {
        return {
          content:
            '{"satisfied": true, "confidence": 0.9, "reasoning": "answered"}',
        };
      }
      if (prompt.includes('tool:network/search')) {
        return {
          content: 'Use the verification MCP via the superserver gateway.',
          promptTokens: 20,
          completionTokens: 10,
        };
      }
      return {
        content:
          '```tool_call\n{"name":"network/search","arguments":{"query":"verification MCP"}}\n```',
        promptTokens: 15,
        completionTokens: 8,
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'gnosis-local',
        messages: [{ role: 'user', content: 'Find the verification MCP.' }],
        max_tool_rounds: 4,
      },
      { infer, mcp, randomId: (prefix) => `${prefix}_fixed` },
    );

    expect(mcp.preflightCalls).toHaveLength(1);
    expect(mcp.calls).toEqual([
      { name: 'network/search', args: { query: 'verification MCP' } },
    ]);
    expect(response.id).toBe('chatcmpl_fixed');
    expect(response.choices[0]?.message.content).toContain(
      'verification MCP',
    );
    expect(response.tools_used).toEqual(['network/search']);
    expect(response.agentic.toolPreflight.toolCount).toBe(1);
    expect(response.agentic.rounds).toBe(2);
    // Aeon-12 economy: the successful network/search call should have
    // scored real points and left the dial un-winded, proving the economy
    // is actually wired through the real per-round tool-result path, not
    // just unit-tested in isolation.
    expect(response.agentic.economy.score).toBeGreaterThan(0);
    expect(response.agentic.economy.winded).toBe(false);
    expect(response.agentic.economy.weight).toBe(response.agentic.economy.ceiling);
  });

  it('does not let a corpus-common word bury the genuinely relevant tool (live regression)', async () => {
    // Reconstructs the real live finding: a query containing "verification"
    // and "MCP" tied a flood of unrelated tools together because those words
    // are common boilerplate across the catalog, burying network/search —
    // the actually relevant tool. 30 noise tools mimic that boilerplate;
    // network/search's own description also happens to say "MCP" once, which
    // is exactly why the corpus-frequency filter (not a hardcoded exclusion)
    // is required — it must earn its score from "search"/"registry", not
    // survive by omitting "mcp" from its own text.
    const noiseTools: AgenticToolDefinition[] = Array.from({ length: 30 }, (_, i) => ({
      type: 'function' as const,
      function: {
        name: `gnosis/theorem_${i}`,
        description:
          'Part of the MCP verification ledger. See also formal proof obligations and MCP compliance.',
      },
    }));
    const mcp = new FakeMcpClient([...noiseTools, SEARCH_TOOL]);
    const infer = vi.fn(async () => ({ content: 'Relevant preflighted MCP.' }));

    const response = await runAgenticChatCompletion(
      {
        model: 'gnosis-local',
        messages: [
          { role: 'user', content: 'Search the tool registry for a verification MCP.' },
        ],
        max_tool_rounds: 2,
        execute_tools: false,
      },
      { infer, mcp },
    );

    const c0 = response.agentic.metacognitionTrace.find((entry) => entry.layer === 'C0');
    const candidates = (c0?.data as { candidates?: Array<{ toolName: string; score: number }> })
      ?.candidates ?? [];
    const searchCandidate = candidates.find((c) => c.toolName === 'network/search');
    const noiseScores = candidates
      .filter((c) => c.toolName !== 'network/search')
      .map((c) => c.score);

    expect(searchCandidate).toBeDefined();
    expect(searchCandidate!.score).toBeGreaterThan(Math.max(0, ...noiseScores));
  });

  it('runs high-confidence activation before the first chat inference', async () => {
    const activatedTool: AgenticToolDefinition = {
      ...SEARCH_TOOL,
      activation: {
        patterns: ['find|search'],
        keywords: ['verification'],
        skipReview: true,
        threshold: 0.7,
      },
    };
    const mcp = new FakeMcpClient([activatedTool]);
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      if (request.purpose === 'intent-evaluation') {
        return {
          content:
            '{"satisfied": true, "confidence": 0.9, "reasoning": "tool result summarized"}',
        };
      }
      const prompt = renderMessagesForPrompt(request.messages);
      expect(prompt).toContain('tool:network/search');
      return {
        content: 'The superserver registry points to verification tooling.',
      };
    });

    const messages: AgenticChatMessage[] = [
      { role: 'user', content: 'Search for verification tooling.' },
    ];
    const response = await runAgenticChatCompletion(
      {
        model: 'gnosis-local',
        messages,
        max_tool_rounds: 2,
      },
      { infer, mcp },
    );

    expect(mcp.calls).toHaveLength(1);
    expect(infer).toHaveBeenCalledWith(
      expect.objectContaining({ purpose: 'chat' }),
    );
    expect(response.agentic.metacognitionTrace).toEqual(
      expect.arrayContaining([
        expect.objectContaining({ layer: 'C0' }),
        expect.objectContaining({ layer: 'C1' }),
        expect.objectContaining({ layer: 'C2' }),
        expect.objectContaining({ layer: 'C3' }),
      ]),
    );
  });

  it('threads Thoth gate telemetry through prompt, nudge, and action trace', async () => {
    const metrics = canonicalThothGateTelemetryMetrics();
    const prompts: string[] = [];
    let chatCalls = 0;
    let evaluationCalls = 0;
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      prompts.push(renderMessagesForPrompt(request.messages));
      if (request.purpose === 'intent-evaluation') {
        evaluationCalls += 1;
        if (evaluationCalls > 1) {
          return {
            content:
              '{"satisfied": true, "confidence": 0.95, "reasoning": "boundary stabilized"}',
          };
        }
        return {
          content:
            '{"satisfied": false, "confidence": 0.95, "reasoning": "needs oath-stable next step", "suggestedNextAction": "stabilize the action boundary"}',
        };
      }
      chatCalls += 1;
      return {
        content:
          chatCalls === 1
            ? 'Initial answer.'
            : 'Final answer with the action boundary stabilized.',
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'gnosis-local',
        messages: [{ role: 'user', content: 'Thread Thoth telemetry.' }],
        auto_tools: false,
        max_tool_rounds: 3,
        thothGateTelemetry: metrics,
      },
      { infer },
    );

    expect(prompts[0]).toContain('Thoth gate telemetry follows');
    expect(prompts[0]).toContain('oath: aligned=0.85');
    expect(prompts[0]).toContain('Prompt/nudge/action contract');
    expect(prompts.at(-1)).toContain('Thoth gate hint: highestPressure=');
    expect(response.agentic.nudges).toBe(1);
    expect(response.agentic.metacognitionTrace).toEqual(
      expect.arrayContaining([
        expect.objectContaining({
          layer: 'C0',
          message: 'Thoth gate telemetry threaded into prompt/nudge/action',
        }),
      ]),
    );
  });

  it('lets Thoth metacog select local oath self-management tools', async () => {
    const metrics = canonicalThothGateTelemetryMetrics();
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      if (request.purpose === 'intent-evaluation') {
        return {
          content:
            '{"satisfied": true, "confidence": 0.9, "reasoning": "oath programmed"}',
        };
      }
      const prompt = renderMessagesForPrompt(request.messages);
      expect(prompt).toContain('tool:thoth/oath.propose');
      return {
        content: 'Oath ledger updated with a bounded stability invariant.',
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'gnosis-local',
        messages: [
          {
            role: 'user',
            content: 'Make an oath to keep actions non-authoritative.',
          },
        ],
        max_tool_rounds: 2,
        thothGateTelemetry: metrics,
        metacognition: { reviewToolActivations: false },
      },
      { infer, randomId: (prefix) => `${prefix}_fixed` },
    );

    expect(response.tools_used).toEqual(['thoth/oath.propose']);
    expect(response.agentic.toolPreflight.toolCount).toBeGreaterThanOrEqual(3);
    expect(response.agentic.metacognitionTrace).toEqual(
      expect.arrayContaining([
        expect.objectContaining({ layer: 'C2' }),
        expect.objectContaining({ layer: 'C3' }),
        expect.objectContaining({
          layer: 'C4',
          message: 'Thoth oath telemetry observed: oath.proposed',
        }),
      ]),
    );
  });

  it('uses the native Qwen <tool_call> convention when runtime.nativeToolFamily is set', async () => {
    const mcp = new FakeMcpClient([SEARCH_TOOL]);
    const prompts: string[] = [];
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      const prompt = renderMessagesForPrompt(request.messages);
      prompts.push(prompt);
      if (request.purpose === 'intent-evaluation') {
        return {
          content: '{"satisfied": true, "confidence": 0.9, "reasoning": "answered"}',
        };
      }
      if (prompt.includes('tool:network/search')) {
        return { content: 'Found it via the native Qwen path.' };
      }
      // The real model's native output shape — not the generic fenced block.
      return {
        content:
          '<tool_call>\n{"name": "network/search", "arguments": {"query": "verification MCP"}}\n</tool_call>',
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'qwen2.5-7b',
        messages: [{ role: 'user', content: 'Find the verification MCP.' }],
        max_tool_rounds: 4,
      },
      { infer, mcp, nativeToolFamily: 'qwen' },
    );

    // The system prompt uses Qwen's real declaration tags, not the generic
    // "## TOOL CALLING INSTRUCTIONS" / ```tool_call convention.
    expect(prompts[0]).toContain('<tools>');
    expect(prompts[0]).toContain('<tool_call></tool_call>');
    expect(prompts[0]).not.toContain('## TOOL CALLING INSTRUCTIONS');

    expect(mcp.calls).toEqual([
      { name: 'network/search', args: { query: 'verification MCP' } },
    ]);
    expect(response.tools_used).toEqual(['network/search']);
    expect(response.choices[0]?.message.content).toContain('native Qwen path');

    // The `tools` array reaches runtime.infer (needed by Mistral's preamble;
    // harmless for Qwen, which declares tools via message content instead).
    expect(infer).toHaveBeenCalledWith(
      expect.objectContaining({
        tools: expect.arrayContaining([expect.objectContaining({ function: expect.objectContaining({ name: 'network/search' }) })]),
      }),
    );
  });

  it('uses the native Mistral [TOOL_CALLS] convention and preserves the model-emitted id through the round-trip', async () => {
    const mcp = new FakeMcpClient([SEARCH_TOOL]);
    const captured: { secondRoundMessages: AgenticChatMessage[] | null } = {
      secondRoundMessages: null,
    };
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      if (request.purpose === 'intent-evaluation') {
        return {
          content: '{"satisfied": true, "confidence": 0.9, "reasoning": "answered"}',
        };
      }
      const prompt = renderMessagesForPrompt(request.messages);
      if (prompt.includes('tool:network/search')) {
        captured.secondRoundMessages = request.messages;
        return { content: 'Found it via the native Mistral path.' };
      }
      // The real model's native output shape, including the V3 9-char id.
      return {
        content:
          '[TOOL_CALLS] [{"name": "network/search", "arguments": {"query": "verification MCP"}, "id": "VvvODy9mT"}]',
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'mistral-7b',
        messages: [{ role: 'user', content: 'Find the verification MCP.' }],
        max_tool_rounds: 4,
      },
      { infer, mcp, nativeToolFamily: 'mistral-v3' },
    );

    expect(mcp.calls).toEqual([
      { name: 'network/search', args: { query: 'verification MCP' } },
    ]);
    expect(response.choices[0]?.message.content).toContain('native Mistral path');
    // The model's own 9-char id survives from the parsed tool_calls message
    // into the tool-result message that feeds the second round — this is
    // what lets openai-server.ts's [TOOL_RESULTS] segment reference the
    // matching call_id with zero extra tracking state.
    expect(captured.secondRoundMessages).not.toBeNull();
    const roundMessages = captured.secondRoundMessages!;
    const toolResultMessage = roundMessages.find((m) => m.role === 'tool');
    expect(toolResultMessage?.tool_call_id).toBe('VvvODy9mT');
    const assistantCallMessage = roundMessages.find(
      (m) => m.role === 'assistant' && m.tool_calls,
    );
    expect(assistantCallMessage?.tool_calls?.[0]?.id).toBe('VvvODy9mT');
  });

  it('falls back to the generic fenced-block parser when the native family finds no markers', async () => {
    // A model pointed at a native family that free-texts instead of using the
    // native convention must still be parsed correctly via the generic path.
    const mcp = new FakeMcpClient([SEARCH_TOOL]);
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      if (request.purpose === 'intent-evaluation') {
        return {
          content: '{"satisfied": true, "confidence": 0.9, "reasoning": "answered"}',
        };
      }
      const prompt = renderMessagesForPrompt(request.messages);
      if (prompt.includes('tool:network/search')) {
        return { content: 'Answered via the generic fallback.' };
      }
      return {
        content:
          '```tool_call\n{"name":"network/search","arguments":{"query":"verification MCP"}}\n```',
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'qwen2.5-7b',
        messages: [{ role: 'user', content: 'Find the verification MCP.' }],
        max_tool_rounds: 4,
      },
      { infer, mcp, nativeToolFamily: 'qwen' },
    );

    expect(mcp.calls).toEqual([
      { name: 'network/search', args: { query: 'verification MCP' } },
    ]);
    expect(response.choices[0]?.message.content).toContain('generic fallback');
  });

  it('uses the native Gemma4 mini-DSL convention when runtime.nativeToolFamily is "gemma4" (experimental)', async () => {
    const mcp = new FakeMcpClient([SEARCH_TOOL]);
    const prompts: string[] = [];
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      const prompt = renderMessagesForPrompt(request.messages);
      prompts.push(prompt);
      if (request.purpose === 'intent-evaluation') {
        return {
          content: '{"satisfied": true, "confidence": 0.9, "reasoning": "answered"}',
        };
      }
      if (prompt.includes('tool:network/search')) {
        return { content: 'Found it via the gated Gemma4 path.' };
      }
      return {
        content: '<|tool_call>call:network/search{query:<|"|>verification MCP<|"|>}<tool_call|>',
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'gemma4-scratch',
        messages: [{ role: 'user', content: 'Find the verification MCP.' }],
        max_tool_rounds: 4,
      },
      { infer, mcp, nativeToolFamily: 'gemma4' },
    );

    expect(prompts[0]).toContain('<|tool>declaration:network/search');
    expect(mcp.calls).toEqual([
      { name: 'network/search', args: { query: 'verification MCP' } },
    ]);
    expect(response.choices[0]?.message.content).toContain('gated Gemma4 path');
  });

  it('regression: byte-identical behavior when nativeToolFamily is unset (Part A/B non-regression)', async () => {
    const mcp = new FakeMcpClient([SEARCH_TOOL]);
    const infer = vi.fn(async (request: TextGenerationRequest) => {
      const prompt = renderMessagesForPrompt(request.messages);
      if (request.purpose === 'intent-evaluation') {
        return {
          content: '{"satisfied": true, "confidence": 0.9, "reasoning": "answered"}',
        };
      }
      if (prompt.includes('tool:network/search')) {
        return {
          content: 'Use the verification MCP via the superserver gateway.',
          promptTokens: 20,
          completionTokens: 10,
        };
      }
      return {
        content:
          '```tool_call\n{"name":"network/search","arguments":{"query":"verification MCP"}}\n```',
        promptTokens: 15,
        completionTokens: 8,
      };
    });

    const response = await runAgenticChatCompletion(
      {
        model: 'gnosis-local',
        messages: [{ role: 'user', content: 'Find the verification MCP.' }],
        max_tool_rounds: 4,
      },
      { infer, mcp, randomId: (prefix) => `${prefix}_fixed` },
    );

    expect(mcp.calls).toEqual([
      { name: 'network/search', args: { query: 'verification MCP' } },
    ]);
    expect(response.id).toBe('chatcmpl_fixed');
    expect(response.choices[0]?.message.content).toContain('verification MCP');
    expect(response.tools_used).toEqual(['network/search']);
    expect(response.agentic.rounds).toBe(2);
  });
});
